local function get_db_connection()
    local pg = pgmoon.new({
        host = os.getenv("DB_HOST") or "127.0.0.1",
        port = tonumber(os.getenv("DB_PORT")) or 5432,
        database = os.getenv("DB_NAME") or "myapp",
        user = os.getenv("DB_USER") or "myapp_user",
        password = os.getenv("DB_PASSWORD") or "secret",
        ssl = false
    })

    local ok, err = pg:connect()
    if not ok then
        return nil, "failed to connect to database: " .. tostring(err)
    end

    return pg
end

local function close_db_connection(pg)
    if pg then
        pg:keepalive(10000, 50)
    end
end

